    'Science-Based PPL',
    'Science-Based PPL - 12w 6x/wk',
    'High',
    true,
    'Evidence-based Push/Pull/Legs split hitting each muscle 2x/week with optimal volume',
    'Hypertrophy/Muscle Building'
FROM program_variants pv
JOIN branded_programs bp ON bp.id = pv.base_program_id
WHERE bp.name = 'Science-Based PPL'
  AND pv.duration_weeks = 12
  AND pv.sessions_per_week = 6
ON CONFLICT DO NOTHING;

